    public Object parseMarket(Object market)
    {
        //
        //   {
        //     "symbol": "PERP_BTC_USDC",
        //     "quote_min": 123,
        //     "quote_max": 100000,
        //     "quote_tick": 0.1,
        //     "base_min": 0.00001,
        //     "base_max": 20,
        //     "base_tick": 0.00001,
        //     "min_notional": 1,
        //     "price_range": 0.02,
        //     "price_scope": 0.4,
        //     "std_liquidation_fee": 0.03,
        //     "liquidator_fee": 0.015,
        //     "claim_insurance_fund_discount": 0.0075,
        //     "funding_period": 8,
        //     "cap_funding": 0.000375,
        //     "floor_funding": -0.000375,
        //     "interest_rate": 0.0001,
        //     "created_time": 1684140107326,
        //     "updated_time": 1685345968053,
        //     "base_mmr": 0.05,
        //     "base_imr": 0.1,
        //     "imr_factor": 0.0002512,
        //     "liquidation_tier": "1"
        //   }
        //
        Object marketId = this.safeString(market, "symbol");
        Object parts = Helpers.split(marketId, "_");
        Object marketType = "swap";
        Object baseId = this.safeString(parts, 1);
        Object quoteId = this.safeString(parts, 2);
        Object base = this.safeCurrencyCode(baseId);
        Object quote = this.safeCurrencyCode(quoteId);
        Object settleId = this.safeString(parts, 2);
        Object settle = this.safeCurrencyCode(settleId);
        Object symbol = Helpers.add(Helpers.add(Helpers.add(Helpers.add(base, "/"), quote), ":"), settle);
        final Object finalBase = base;
        return new java.util.HashMap<String, Object>() {{
            put( "id", marketId );
            put( "symbol", symbol );
            put( "base", finalBase );
            put( "quote", quote );
            put( "settle", settle );
            put( "baseId", baseId );
            put( "quoteId", quoteId );
            put( "settleId", settleId );
            put( "type", marketType );
            put( "spot", false );
            put( "margin", false );
            put( "swap", true );
            put( "future", false );
            put( "option", false );
            put( "active", null );
            put( "contract", true );
            put( "linear", true );
            put( "inverse", false );
            put( "contractSize", ModetradeCore.this.parseNumber("1") );
            put( "expiry", null );
            put( "expiryDatetime", null );
            put( "strike", null );
            put( "optionType", null );
            put( "precision", new java.util.HashMap<String, Object>() {{
                put( "amount", ModetradeCore.this.safeNumber(market, "base_tick") );
                put( "price", ModetradeCore.this.safeNumber(market, "quote_tick") );
            }} );
            put( "limits", new java.util.HashMap<String, Object>() {{
                put( "leverage", new java.util.HashMap<String, Object>() {{
                    put( "min", null );
                    put( "max", null );
                }} );
                put( "amount", new java.util.HashMap<String, Object>() {{
                    put( "min", ModetradeCore.this.safeNumber(market, "base_min") );
                    put( "max", ModetradeCore.this.safeNumber(market, "base_max") );
                }} );
                put( "price", new java.util.HashMap<String, Object>() {{
                    put( "min", ModetradeCore.this.safeNumber(market, "quote_min") );
                    put( "max", ModetradeCore.this.safeNumber(market, "quote_max") );
                }} );
                put( "cost", new java.util.HashMap<String, Object>() {{
                    put( "min", ModetradeCore.this.safeNumber(market, "min_notional") );
                    put( "max", null );
                }} );
            }} );
            put( "created", ModetradeCore.this.safeInteger(market, "created_time") );
            put( "info", market );
        }};
    }

