    public Object parsePosition(Object position, Object... optionalArgs)
    {
        //
        // {
        //     "IMR_withdraw_orders": 0.1,
        //     "MMR_with_orders": 0.05,
        //     "average_open_price": 27908.14386047,
        //     "cost_position": -139329.358492,
        //     "est_liq_price": 117335.92899428,
        //     "fee_24_h": 123,
        //     "imr": 0.1,
        //     "last_sum_unitary_funding": 70.38,
        //     "mark_price": 27794.9,
        //     "mmr": 0.05,
        //     "pending_long_qty": 123,
        //     "pending_short_qty": 123,
        //     "pnl_24_h": 123,
        //     "position_qty": -5,
        //     "settle_price": 27865.8716984,
        //     "symbol": "PERP_BTC_USDC",
        //     "timestamp": 1685429350571,
        //     "unsettled_pnl": 354.858492
        // }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object contract = this.safeString(position, "symbol");
        market = this.safeMarket(contract, market);
        Object size = this.safeString(position, "position_qty");
        Object side = null;
        if (Helpers.isTrue(Precise.stringGt(size, "0")))
        {
            side = "long";
        } else
        {
            side = "short";
        }
        Object contractSize = this.safeString(market, "contractSize");
        Object markPrice = this.safeString(position, "mark_price");
        Object timestamp = this.safeInteger(position, "timestamp");
        Object entryPrice = this.safeString(position, "average_open_price");
        Object unrealisedPnl = this.safeString(position, "unsettled_pnl");
        size = Precise.stringAbs(size);
        Object notional = Precise.stringMul(size, markPrice);
        final Object finalMarket = market;
        final Object finalSize = size;
        final Object finalSide = side;
        return this.safePosition(new java.util.HashMap<String, Object>() {{
            put( "info", position );
            put( "id", null );
            put( "symbol", ModetradeCore.this.safeString(finalMarket, "symbol") );
            put( "timestamp", timestamp );
            put( "datetime", ModetradeCore.this.iso8601(timestamp) );
            put( "lastUpdateTimestamp", null );
            put( "initialMargin", null );
            put( "initialMarginPercentage", null );
            put( "maintenanceMargin", null );
            put( "maintenanceMarginPercentage", null );
            put( "entryPrice", ModetradeCore.this.parseNumber(entryPrice) );
            put( "notional", ModetradeCore.this.parseNumber(notional) );
            put( "leverage", null );
            put( "unrealizedPnl", ModetradeCore.this.parseNumber(unrealisedPnl) );
            put( "contracts", ModetradeCore.this.parseNumber(finalSize) );
            put( "contractSize", ModetradeCore.this.parseNumber(contractSize) );
            put( "marginRatio", null );
            put( "liquidationPrice", ModetradeCore.this.safeNumber(position, "est_liq_price") );
            put( "markPrice", ModetradeCore.this.parseNumber(markPrice) );
            put( "lastPrice", null );
            put( "collateral", null );
            put( "marginMode", "cross" );
            put( "marginType", null );
            put( "side", finalSide );
            put( "percentage", null );
            put( "hedged", null );
            put( "stopLossPrice", null );
            put( "takeProfitPrice", null );
        }});
    }

